-- Duc Chinh Jewelry product seed data.
-- Import after running Laravel migrations, or run php artisan migrate:fresh --seed when PHP/Docker is available.
CREATE DATABASE IF NOT EXISTS trangsuc CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE trangsuc;
SET NAMES utf8mb4;
SET @seed_now = NOW();

ON DUPLICATE KEY UPDATE
  name = VALUES(name),
  price = VALUES(price),
  image = VALUES(image),
  description = VALUES(description),
  category = VALUES(category),
  is_best_seller = VALUES(is_best_seller),
  stock = VALUES(stock),
  status = VALUES(status),
  updated_at = VALUES(updated_at);